+
+  // GET /files/all?ref=...
+  if (rest === "files/all" && method === "GET") {
+    return sendApiAction(store, request, repoPath, "list-all-files");
+  }
+
+  // POST /commits
+  if (rest === "commits" && method === "POST") {
+    return sendApiAction(store, request, repoPath, "commit");
+  }
